const jwt = require("jsonwebtoken");
const admin = require('../config/firebase');
const User = require("../models/User");

exports.protect = async (req, res, next) => {
  let token;

  if (req.headers.authorization && req.headers.authorization.startsWith("Bearer")) {
    token = req.headers.authorization.split(" ")[1];
  }

  if (!token) {
    return res.status(401).json({ success: false, error: "Not authorized to access this route" });
  }

  try {
    let decoded;
    
    // Try Firebase ID Token first (if Firebase is configured)
    if (admin) {
      try {
        decoded = await admin.auth().verifyIdToken(token);
        req.firebaseUser = decoded;
        req.user = await User.findOne({ firebaseUid: decoded.uid }).select("-password");
        if (req.user) {
          if (!req.user.isActive) {
            return res.status(401).json({ success: false, error: "Account is deactivated" });
          }
          return next();
        }
      } catch (firebaseErr) {
        // If Firebase fails, continue to JWT fallback
        console.debug('Firebase verification failed, trying JWT...');
      }
    }

    // Fallback to JWT
    decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = await User.findById(decoded.id).select("-password");

    if (!req.user) {
      return res.status(401).json({ success: false, error: "User not found" });
    }

    if (!req.user.isActive) {
      return res.status(401).json({ success: false, error: "Account is deactivated" });
    }

    next();
  } catch (err) {
    return res.status(401).json({ success: false, error: "Token is invalid or expired" });
  }
};

// Authorize specific roles
exports.authorize = (...roles) => {
  return (req, res, next) => {
    if (!roles.includes(req.user.role)) {
      return res.status(403).json({
        success: false,
        error: `Role '${req.user.role}' is not authorized to access this route`,
      });
    }
    next();
  };
};

// Optional auth (doesn't fail if no token)
exports.optionalAuth = async (req, res, next) => {
  let token;
  if (req.headers.authorization && req.headers.authorization.startsWith("Bearer")) {
    token = req.headers.authorization.split(" ")[1];
  }
  if (token) {
    try {
      const decoded = jwt.verify(token, process.env.JWT_SECRET);
      req.user = await User.findById(decoded.id).select("-password");
    } catch (err) {
      req.user = null;
    }
  }
  next();
};
